module Gray_counter_4(
   input                clk,
   input                rst_n,
   output reg [3:0]     Q  
);
    reg [3:0] gray_counter;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) gray_counter <= 4'd0;
        else gray_counter <= gray_counter + 1;
    end

    always@* begin
        Q = gray_counter ^ (gray_counter >> 1);
    end
endmodule
